SELECT TBP.ID, TBP.POST_TITLE, TBP.POST_CONTENT, TBP.POST_CREATE_AT, TBP.POST_VIEW_COUNT, TBP.POST_TYPE, TBP.USER_ID, TBU.USER_LEVEL, TBU.USER_THUMBNAIL_URL, TBU.USER_NICKNAME, TBU.USER_THUMBNAIL_NAME, COUNT(TBC.ID) AS COMMENT_COUNT FROM TBL_POST TBP JOIN TBL_USER TBU ON TBP.USER_ID = TBU.ID LEFT JOIN TBL_COMMENT TBC ON TBP.ID = TBC.POST_ID WHERE TBP.POST_TYPE IN ('JS', 'JAVA', 'ORACLE') AND ( LOWER(TBP.POST_TITLE) LIKE '%' || LOWER(#{fullKeyword}) || '%' OR LOWER(TBP.POST_CONTENT) LIKE '%' || LOWER(#{fullKeyword}) || '%'
OR LOWER(TBP.POST_TITLE) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(TBP.POST_CONTENT) LIKE '%' || LOWER(#{keyword}) || '%'
) GROUP BY TBP.ID, TBP.POST_TITLE, TBP.POST_CONTENT, TBP.POST_CREATE_AT, TBP.POST_VIEW_COUNT, TBP.POST_TYPE, TBP.USER_ID, TBU.USER_LEVEL, TBU.USER_THUMBNAIL_URL, TBU.USER_NICKNAME, TBU.USER_THUMBNAIL_NAME ORDER BY TBP.POST_CREATE_AT DESC

SELECT TBP.ID, TBP.POST_TITLE, TBP.POST_CONTENT, TBP.POST_CREATE_AT, TBP.POST_VIEW_COUNT, TBP.POST_TYPE, TBP.USER_ID, TBU.USER_LEVEL, TBU.USER_THUMBNAIL_URL, TBU.USER_NICKNAME, TBU.USER_THUMBNAIL_NAME, COUNT(TBC.ID) AS COMMENT_COUNT FROM TBL_POST TBP JOIN TBL_USER TBU ON TBP.USER_ID = TBU.ID LEFT JOIN TBL_COMMENT TBC ON TBP.ID = TBC.POST_ID WHERE TBP.POST_TYPE = 'OPEN' AND ( LOWER(TBP.POST_TITLE) LIKE '%' || LOWER(#{fullKeyword}) || '%' OR LOWER(TBP.POST_CONTENT) LIKE '%' || LOWER(#{fullKeyword}) || '%'
OR LOWER(TBP.POST_TITLE) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(TBP.POST_CONTENT) LIKE '%' || LOWER(#{keyword}) || '%'
) GROUP BY TBP.ID, TBP.POST_TITLE, TBP.POST_CONTENT, TBP.POST_CREATE_AT, TBP.POST_VIEW_COUNT, TBP.POST_TYPE, TBP.USER_ID, TBU.USER_LEVEL, TBU.USER_THUMBNAIL_URL, TBU.USER_NICKNAME, TBU.USER_THUMBNAIL_NAME ORDER BY TBP.POST_CREATE_AT DESC
